#!/usr/bin/env node
'use strict';

/*
 * Generate the executable F27 install checklist from the marked source block
 * in docs/ops/F27_INSTALL_RUNBOOK.md. The generated file carries the SHA-256
 * of the complete runbook, so any prose or gate change requires regeneration.
 */

const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const REPO_ROOT = path.resolve(__dirname, '..');
const RUNBOOK = path.join(REPO_ROOT, 'docs', 'ops', 'F27_INSTALL_RUNBOOK.md');
const CHECKLIST = path.join(REPO_ROOT, 'docs', 'ops', 'F27_INSTALL_CHECKLIST.md');
const BEGIN = '<!-- F27_INSTALL_CHECKLIST_BEGIN -->';
const END = '<!-- F27_INSTALL_CHECKLIST_END -->';

function sha256(bytes) {
  return crypto.createHash('sha256').update(bytes).digest('hex');
}

function extractChecklist(runbookText) {
  const start = runbookText.indexOf(BEGIN);
  const finish = runbookText.indexOf(END);
  if (start < 0 || finish < 0 || finish <= start || runbookText.indexOf(BEGIN, start + 1) >= 0
      || runbookText.indexOf(END, finish + 1) >= 0) {
    throw new Error('runbook must contain exactly one ordered checklist source block');
  }
  const body = runbookText.slice(start + BEGIN.length, finish).trim();
  if (!body.startsWith('## Operator checklist') || !body.includes('- [ ]')) {
    throw new Error('runbook checklist source is incomplete');
  }
  return body;
}

function renderChecklist(runbookBytes) {
  const text = runbookBytes.toString('utf8');
  const body = extractChecklist(text);
  return [
    '# F27 generated install checklist',
    '',
    '> Generated by `node scripts/f27-install-checklist.js --write`.',
    '> Do not edit this file directly. The runbook is the mechanical source of truth.',
    `> Complete-runbook SHA-256: \`${sha256(runbookBytes)}\``,
    '',
    body,
    '',
  ].join('\n');
}

function run(mode, runbookPath = RUNBOOK, checklistPath = CHECKLIST) {
  const runbookBytes = fs.readFileSync(runbookPath);
  const expected = renderChecklist(runbookBytes);
  if (mode === '--write') {
    fs.writeFileSync(checklistPath, expected, 'utf8');
    return { status: 'PASS', mode: 'write', runbook_sha256: sha256(runbookBytes) };
  }
  if (mode === '--check') {
    const actual = fs.existsSync(checklistPath) ? fs.readFileSync(checklistPath, 'utf8') : '';
    if (actual !== expected) throw new Error('generated F27 install checklist is stale');
    return { status: 'PASS', mode: 'check', runbook_sha256: sha256(runbookBytes) };
  }
  throw new Error('usage: node scripts/f27-install-checklist.js --write|--check');
}

if (require.main === module) {
  try {
    if (process.argv.length !== 3) throw new Error('exactly one mode is required');
    console.log(JSON.stringify(run(process.argv[2])));
  } catch (error) {
    console.error(`f27-install-checklist: ${String(error && error.message || error)}`);
    process.exit(1);
  }
}

module.exports = { BEGIN, END, extractChecklist, renderChecklist, run, sha256 };
